// Contributo fattoriale per asset+indice di HIST_MONTHLY; 0 fuori range o asset ignoto.
function ff5ContribAt(asset, idx) {
  const arr = FF5_CONTRIB[asset];
  if (!arr) return 0;
  const i = idx - FF5_CONTRIB_START;
  return (i >= 0 && i < arr.length) ? arr[i] : 0;
}

