// Rendimento REITs (EUR) per un indice di HIST_MONTHLY; null fuori dal range coperto
// (il chiamante usa il rendimento azionario come fallback per i mesi pre-1979).
function reitsReturnAt(idx) {
  const i = idx - REITS_START;
  return (i >= 0 && i < HIST_REITS.length) ? HIST_REITS[i] : null;
}

