// globale ma NON una proprietà su `window` (a differenza di `var`). Il
// lookup dinamico "window[key]" usato da _bondRetReal() (backtest.js) e da
// _mcBondRet() qui sotto restituiva quindi SEMPRE undefined, qualunque
// scadenza/paese fosse selezionato nel portafoglio custom: il codice
// ripiegava silenziosamente sulla serie aggregata HIST_MONTHLY[][1] per
// OGNI combinazione (es. Gov Euro 1-3Y e Gov USA Ultra Long 30Y
// producevano risultati identici nel backtest, nel bootstrap e nello
// stress test di sequenza/crisi). Fix: registro esplicito indicizzato per
// nome, usato al posto di window[key] in tutti i punti di lookup.
const HIST_BOND_SERIES = {
  HIST_USB_2Y, HIST_USB_5Y, HIST_USB_10Y, HIST_USB_30Y, HIST_USB_3M,
  HIST_EUB_2Y, HIST_EUB_5Y, HIST_EUB_10Y, HIST_EUB_30Y, HIST_EUB_3M,
  HIST_GOV_GLOBAL
};
if (typeof window !== 'undefined') window.HIST_BOND_SERIES = HIST_BOND_SERIES;

// FIX 2026-07-01: gen1970-dic1974 (indici 0-59) le curve USA sono collassate a coppie
// byte-identiche (HIST_USB_2Y=HIST_USB_5Y, HIST_USB_10Y=HIST_USB_30Y): GS2 e GS30 non
// esistevano su FRED prima del 1976/1977 e si è usato lo stesso proxy per le scadenze
// vicine. Usarle come dati "per scadenza reali" in quella finestra crea una falsa
// correlazione perfetta 2Y/5Y e 10Y/30Y proprio nella finestra della crisi 1973-74 OPEC.
// bondSeriesReturnAt() centralizza l'accesso con la stessa soglia usata per le azioni
// regionali (HIST_EQ_REGIONAL_START): sotto soglia ritorna null e il chiamante ricade
// sull'aggregato (HIST_MONTHLY[.][1]), esattamente come già avviene per REITs/EM pre-start.
const HIST_BOND_DURATION_START = 60; // 1975-01: prima le curve USA per scadenza non sono indipendenti
function bondSeriesReturnAt(key, idx) {
  if (idx < HIST_BOND_DURATION_START) return null;
  const arr = HIST_BOND_SERIES[key];
  return (arr && idx >= 0 && idx < arr.length) ? arr[idx] : null;
}
if (typeof window !== 'undefined') window.bondSeriesReturnAt = bondSeriesReturnAt;

// Rendimento Emergenti (EUR) per un indice di HIST_MONTHLY; null fuori dal range
// coperto (il chiamante usa il rendimento azionario come fallback pre-lug-1989).
function emReturnAt(idx) {
  const i = idx - EM_START;
  return (i >= 0 && i < HIST_EM.length) ? HIST_EM[i] : null;
}

