// FIX 2026-07-02 (bis): anche HIST_EQ_EUROPE ora ha dati reali (curvo/MSCI Europe)
// dall'intero periodo gen1970-dic2000 (idx 0-359), sostituendo la ricomposizione
// World+FF. HIST_EQ_USA e HIST_EQ_EUROPE non sono piu' identiche pre-1975: la falsa
// correlazione perfetta (rho=1) descritta sopra e' risolta con dati regionali indipendenti veri.
const HIST_EQ_EUROPE_START = 0;
// FIX 2026-07-02: HIST_EQ_USA ora ha dati reali (curvo/MSCI) anche gen1970-dic2000 (idx 1-359),
// sostituendo la ricomposizione World+FF. Solo l'indice 0 (gen1970) resta proxy World
// per assenza del singolo dato mensile. HIST_EQ_USA_START riflette questo.
const HIST_EQ_USA_START = 0; // FIX 2026-07-04: idx 0 ora e' dato reale (curvo), come HIST_EQ_EUROPE_START

// Accesso serie azionarie regionali reali (USA, Europa). Ritorna null prima dello start
// "fisico" dell'array e prima di HIST_EQ_REGIONAL_START (vedi nota sopra).
function eqUsaReturnAt(idx) {
  if (typeof HIST_EQ_USA === 'undefined') return null;
  return (idx >= HIST_EQ_USA_START && idx < HIST_EQ_USA.length && HIST_EQ_USA[idx] !== 0) ? HIST_EQ_USA[idx] : null;
}
function eqEuropeReturnAt(idx) {
  if (typeof HIST_EQ_EUROPE === 'undefined') return null;
  return (idx >= HIST_EQ_EUROPE_START && idx < HIST_EQ_EUROPE.length && HIST_EQ_EUROPE[idx] !== 0) ? HIST_EQ_EUROPE[idx] : null;
}

function eqReturnWithFactors(eqW, eqRet, idx, fw) {
  fw = fw || {};
  const scvW = fw.scvW || 0;
  const momW = fw.momW || 0;
  const ff5 = fw.ff5W || null;
  const reitsW = fw.reitsW || 0;
  const emW = fw.emW || 0;
  const usaW = fw.usaW || 0;
  const europaW = fw.europaW || 0;
  let factorW = scvW + momW;
  // SV e Momentum: beta di mercato 1 (premio additivo sul mercato pieno)
  let r = scvW * (eqRet + scvSpreadAt(idx)) + momW * (eqRet + momContribAt(idx));
  if (ff5) {
    for (const asset in ff5) {
      const w = ff5[asset] || 0;
      if (w > 0) {
        factorW += w;
        const bMkt = FACTOR_MKT_BETA[asset] || 1; // beta di mercato del fattore (1 = pieno)
        r += w * (bMkt * eqRet + ff5ContribAt(asset, idx));
      }
    }
  }
  // REITs: asset class con rendimento PROPRIO (non un contributo su eqRet). La sua
  // quota usa la serie REITs reale; pre-1979 (null) ripiega sul rendimento azionario.
  if (reitsW > 0) {
    factorW += reitsW;
    const rr = reitsReturnAt(idx);
    r += reitsW * (rr !== null ? rr : eqRet);
  }
  // Mercati Emergenti: come i REITs, asset class con rendimento proprio. La sua quota
  // usa la serie EM reale; pre-lug-1989 (null) ripiega sul rendimento azionario.
  if (emW > 0) {
    factorW += emW;
    const er = emReturnAt(idx);
    r += emW * (er !== null ? er : eqRet);
  }
  // Azioni USA ed Europa: asset class con serie regionale reale propria.
  // Pre-dati (null) ripiegano sul rendimento di mercato World.
  if (usaW > 0) {
    factorW += usaW;
    const ur = eqUsaReturnAt(idx);
    r += usaW * (ur !== null ? ur : eqRet);
  }
  if (europaW > 0) {
    factorW += europaW;
    const er2 = eqEuropeReturnAt(idx);
    r += europaW * (er2 !== null ? er2 : eqRet);
  }
  const eqPureW = Math.max(0, eqW - factorW);
  return eqPureW * eqRet + r;
}

// ── BLOCK BOOTSTRAP sampler ──────────────────────────────────
// Campiona blocchi di 12 mesi contigui (preserva autocorrelazione).
// Per ogni anno simulato: sceglie un blocco casuale da HIST_MONTHLY,
// calcola il rendimento composito del portafoglio per quel blocco,
// e applica una correzione di drift per allineare E[annuale] a PORT.normal.

// Helper MC: rendimento bond del mese (indice assoluto) usando le serie reali per scadenza
// del portafoglio custom corrente. Se non c'è mix reale, ritorna null (→ usa row[1] aggregato).
function _mcBondRet(idx) {
  try {
    if (typeof state === 'undefined' || state.portfolio !== 'custom') return null;
    if (typeof calcCustomParams !== 'function') return null;
    const cp = calcCustomParams();
    const mix = cp.bondMix;
    if (!mix) return null;
    let tot = 0; for (const k in mix) tot += mix[k];
    if (tot <= 0) return null;
    const MEAN = 0.00466;
    // fattore fallback per quota aggregata
    const k_agg = Math.max(0.5, Math.min(1.8, Math.sqrt((cp.obVolW || 0.057) / 0.057)));
    let acc = 0;
    for (const key in mix) {
      const w = mix[key];
      if (key === '_agg') {
        acc += w * (MEAN + k_agg * (HIST_MONTHLY[idx][1] - MEAN));
      } else {
        const br = bondSeriesReturnAt(key, idx);
        acc += w * (br !== null ? br : HIST_MONTHLY[idx][1]);
      }
    }
    return acc / tot;
  } catch (e) { return null; }
}

function sampleBootstrap(eqW, goldW, obW, cashW, portTargetAnnual) {
  const n = HIST_MONTHLY.length;
  const maxStart = n - 12;
  const startIdx = Math.floor(Math.random() * (maxStart + 1));
  // Composita annuale del blocco: [az_sviluppati=0, agg_bond=1, gold=2]
  let annR = 1;
  for (let m = 0; m < 12; m++) {
    const _bi = startIdx + m;
    const row = calibrateHistRow(HIST_MONTHLY[_bi]);
    const _br = (typeof _mcBondRet==='function') ? _mcBondRet(_bi) : null;
    const mR = eqW * row[0] + obW * (_br !== null ? _br : row[1]) + goldW * row[2] + cashW * 0.0025;
    annR *= (1 + mR);
  }
  // Correzione drift: calcola il rendimento medio storico del mix di portafoglio
  // per riscalare e allineare a PORT.normal senza stravolgere la forma distributiva.
  // Shift additivo calibrato in modo che E[bootstrap] = portTargetAnnual.
  // Usiamo uno shift moltiplicativo per preservare la struttura dei ritorni.
  return annR - 1;
}

// Calcola drift medio storico del portafoglio sull'intero dataset
function calcHistMean(eqW, goldW, obW, cashW, scvW, momW, ff5W) {
  // scvW/momW/ff5W (opzionali, default 0/null): quote dei fattori reali (sottoinsiemi
  // di eqW) che usano il rendimento mercato+contributo. Con tutti a 0 il risultato è
  // bit-identico alla versione base (retro-compatibile).
  const fw = { scvW: scvW || 0, momW: momW || 0, ff5W: ff5W || null };
  let total = 1;
  const n = HIST_MONTHLY.length;
  for (let m = 0; m < n; m++) {
    const row = calibrateHistRow(HIST_MONTHLY[m]);
    const eqPart = eqReturnWithFactors(eqW, row[0], m, fw);
    const _brH = (typeof _mcBondRet==='function') ? _mcBondRet(m) : null;
    total *= (1 + eqPart + obW * (_brH !== null ? _brH : row[1]) + goldW * row[2] + cashW * 0.0025);
  }
  return Math.pow(total, 12 / n) - 1; // CAGR mensile → annuale
}

